<?php
namespace Tests\Feature;use App\Models\Character;use App\Models\Hunt;use App\Models\HuntEnemy;use App\Models\Monster;use App\Models\User;use App\Models\Zone;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Database\QueryException;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Tests\TestCase;class HuntSchemaTest extends TestCase{use RefreshDatabase;public function test_encounter_schema_engine_collation_and_delete_rules(){$this->seed(WorldCatalogSeeder::class);foreach(['hunts','hunt_enemies','zone_encounter_sizes'] as $name){$table=DB::selectOne("SELECT ENGINE,TABLE_COLLATION FROM information_schema.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME=?",[$name]);$this->assertSame('InnoDB',$table->ENGINE);$this->assertSame('utf8mb4_unicode_ci',$table->TABLE_COLLATION);}$huntRules=DB::select("SELECT DELETE_RULE FROM information_schema.REFERENTIAL_CONSTRAINTS WHERE CONSTRAINT_SCHEMA=DATABASE() AND TABLE_NAME='hunts'");$this->assertCount(2,$huntRules);foreach($huntRules as $rule)$this->assertSame('RESTRICT',$rule->DELETE_RULE);$enemyRules=DB::select("SELECT DELETE_RULE FROM information_schema.REFERENTIAL_CONSTRAINTS WHERE CONSTRAINT_SCHEMA=DATABASE() AND TABLE_NAME='hunt_enemies' ORDER BY DELETE_RULE");$this->assertSame(['CASCADE','RESTRICT'],array_map(function($r){return$r->DELETE_RULE;},$enemyRules));}public function test_monster_is_restricted_and_hunt_cascades_enemies(){$this->seed(WorldCatalogSeeder::class);$character=Character::factory()->for(User::factory())->create();$result=app(\App\Domain\Hunts\HuntService::class)->start($character,Zone::where('code','grey_oak_forest')->first());$enemy=HuntEnemy::first();try{$enemy->monster->delete();$this->fail('Monster deletion should fail.');}catch(QueryException $e){$this->assertDatabaseHas('monsters',['id'=>$enemy->monster_id]);}Hunt::find($result->huntId())->delete();$this->assertSame(0,HuntEnemy::count());}}
